-- Pronostix v2 - seed Mundial FIFA 2026
-- Fuente principal: FIFA, World Cup 2026 | Match schedule, fixtures & stadiums.
-- Nota: este seed carga los 48 equipos y los 72 partidos de fase de grupos con equipos definidos.
-- Los 32 partidos de eliminación directa tienen cruces oficiales por posición, pero no equipos definidos;
-- con el schema actual (matches.home_team_id/away_team_id NOT NULL) no se insertan para evitar placeholders.

begin;

values ('20260000-0000-0000-0000-000000000001', 'Mundial FIFA 2026', '2026-06-11 19:00:00+00', true)
on conflict (id) do update set
  name = excluded.name,
  starts_at = excluded.starts_at,
  is_active = excluded.is_active,
  updated_at = now();

on conflict (id) do update set
  tournament_id = excluded.tournament_id,
  name = excluded.name,
  code = excluded.code;

on conflict (id) do update set
  tournament_id = excluded.tournament_id,
  home_team_id = excluded.home_team_id,
  away_team_id = excluded.away_team_id,
  kickoff_at = excluded.kickoff_at,
  group_name = excluded.group_name,
  stadium = excluded.stadium,
  city = excluded.city,
  home_score = excluded.home_score,
  away_score = excluded.away_score,
  status = excluded.status,
  updated_at = now();

commit;

